+            disabled ? "opacity-50 cursor-not-allowed" : "cursor-pointer",
+            labelClassName,
+          )}
+          htmlFor={props.id}
+        >
+          {children}
+          {required && <span className="text-red-500">*</span>}
+        </Label>
+      ) : null}
+    </div>
